NTSTATUS F75111GpioPinSetData(int nGpioGroup, int nGpioPin, BOOLEAN bHigh)
{
	if (nGpioGroup < 1 || nGpioGroup > 3)
		return STATUS_INVALID_PARAMETER;

	if (nGpioGroup == 1 || nGpioGroup == 2)
	{
		if (nGpioPin < 0 || nGpioPin > 7)
			return STATUS_INVALID_PARAMETER;
	}
	else if (nGpioGroup == 3)
	{
		if (nGpioPin < 0 || nGpioPin > 3)
			return STATUS_INVALID_PARAMETER;
	}

	NTSTATUS ntStatus = STATUS_SUCCESS;

	ULONG dwData = 0x00;
	ntStatus = F75111GpioGetData(nGpioGroup, &dwData);
	if (bHigh)
		dwData = dwData | (0x01 << nGpioPin);
	else
		dwData = dwData & ~(0x01 << nGpioPin);
	ntStatus = F75111GpioSetData(nGpioGroup, dwData & 0xFF);

	return ntStatus;
}
