		if (wTempAddr == 0x0000 || wTempAddr == 0xFFFF)
			return STATUS_UNSUCCESSFUL;
		else
			ITE8728F_gwGpioBaseAddr = wTempAddr;
	}

	*pwBaseAddr = (USHORT)(ITE8728F_gwGpioBaseAddr + nGpioGroup - 1);

	return ntStatus;
}

